var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"무슨 일이야? 나 지금 한참 파티 중이거든?","JPN":"何の用かしら？　今パーティーを楽しんでいる真っ最中なんだけど？","ENG":"What is it? Can't you see I'm enjoying my party?","TWN":"找我幹嘛？我玩得正開心欸！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"지금 한가하게 파티나 즐기고 있을 때가 아닐 텐데?","JPN":"今呑気にパーティーなんか楽しんでいる場合か？","ENG":"I'm not sure if you should be partying at the moment.","TWN":"你現在還有心情玩嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"이 기사들을 한 번 읽어 보시지.","JPN":"こんな記事が何本も出ているぞ。","ENG":"Why don't you read these articles.","TWN":"你看看這些報導！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>연전연승의 카나리아 스쿼드, 관리국 공인 테스크포스에게 승리.</color>","JPN":"<color=#ffd34c>連戦連勝のカナリア・スクワッド、管理局公認のタスクフォースカンパニーに勝利。</color>","ENG":"<color=#ffd34c>Canary Squad: Win After Win. Victory Against Administration's Official TASKFORCE.</color>","TWN":"<color=#ffd34c>屢戰屢勝的金絲雀小隊，從管理局公認的特遣勢力手中奪勝。</color>"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>신데렐라가 될 수 있을 것인가? 떠오르는 신예의 명과 암.</color>","JPN":"<color=#ffd34c>シンデレラとなるか？　浮かび上がる新星の光と闇。</color>","ENG":"<color=#ffd34c>A Cinderella Story? The Light and Shadow of the Rookie.</color>","TWN":"<color=#ffd34c>灰姑娘的故事會上演嗎？明日之星的成與敗。</color>"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>부모님은 죄인이 아니에요! 삼등 시민의 부상, 정치 공작 우려?</color>","JPN":"<color=#ffd34c>両親に罪はありません！　3等市民の負傷、政治工作の疑い？</color>","ENG":"<color=#ffd34c>My Parents Are Not Guilty! Third-Grade Citizen's Uprising and Concerns of Gutter Politics?</color>","TWN":"<color=#ffd34c>我的父母才不是罪犯！三等市民的崛起，是否有政治性操作？</color>"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"으, 다들 정말 재미없게 산다니까~","JPN":"はぁ、みんな本当つまんない生き方するわね～","ENG":"Ugh, these people need to get a life!","TWN":"嗯，大家真的很無聊欸～"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"즐기고 살아도 모자란 인생인데, 저런 삼류 가십에 시간을 낭비하다니 말이야.","JPN":"楽しむだけでも人生は短いというのに、あんな三流ゴシップに時間を無駄にするなんて。","ENG":"Why waste precious time on these tabloid gossips when there isn't even enough time to enjoy life?","TWN":"人生苦短，玩樂的時間都不夠了，竟然還把時間浪費在這種三流八卦新聞上。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서? 저게 나랑 무슨 상관?","JPN":"それで？　この記事と私になんの関係があるの？","ENG":"So? What's this got to do with me?","TWN":"然後呢？這和我有什麼關係？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"무슨 상관이냐고!? 스폰서가 우습나 보지?","JPN":"なんの関係だと！？　スポンサーを何だと思っているんだ？","ENG":"What does it not have to do with you?! Do you think your sponsors are stupid?","TWN":"和你有什麼關係！？你眼裡還有贊助商嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"삼등 시민 놈들이 본선 진출한 것도 어이가 없는데, 멋대로 녀석들 경기를 보러 갔다면서?","JPN":"3等市民どもが本選進出しただけでも呆れるというのに、勝手にそいつらの試合を見に行ったんだってな？","ENG":"It's bad enough that a third-grade citizen made it into the elimination rounds, but you even went to watch their game!","TWN":"三等市民晉級決賽已經夠荒謬了，你竟然還擅自跑去看他們的比賽？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"그것도 가석방된 지 얼마 안 된 와일러까지 대동해서 말이야!","JPN":"しかも仮釈放されて間もないワイラーと一緒にだ！","ENG":"On top of that, you brought Wyler there when his parole has only just been approved?!","TWN":"更誇張的是還帶著才剛保釋的瓦勒一起！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"하아, 극적인 연출이란 걸 모르네. 요즘 트렌드 몰라?","JPN":"はぁ、劇的な演出ってやつよ。最近のトレンド、知らないの？","ENG":"*Sigh* You guys know nothing about dramatic setting. Keep up with the trends, will you?","TWN":"哀，你們都不懂什麼叫戲劇效果。你們不知道最近觀眾的喜好嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"마무리가 화기애애한 경기는 대중들에게 금방 잊혀지기 마련이라고.","JPN":"最後馴れ合いで終わるような試合は、民衆からはすぐに忘れられるものよ。","ENG":"Matches with happy endings are forgotten by the end of the day.","TWN":"和樂融融的比賽很快就會被大眾遺忘的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 애가 피오네한테 물들어서 독기가 빠졌을까 봐 조금 자극해 본 거야.","JPN":"あの子がフィオネたちに毒されて牙が抜けちゃったんじゃないかな、と思って刺激してみただけ。","ENG":"I was worried the kid lost her venom after her fight with Fione. So I wanted to provoke her.","TWN":"我怕她受到菲奧尼的影響，會滅她的威風，所以我才稍微刺激她一下。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"겨우 그런 이유라고?","JPN":"たかだかその程度の理由だと…？","ENG":"That's your reason?","TWN":"就因為這樣？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"우리가 와일러를 꺼내기 위해 얼마나 투자했는지 잊었나?","JPN":"我々がワイラーを刑務所から出すためにどれだけ投資したか忘れたのか？","ENG":"Did you forget how much we spent just to get Wyler out?","TWN":"你忘記我們為了把瓦勒弄出來費了多大力氣嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"엔터테인먼트는 항상 새로운 자극이 필요한 법이지.","JPN":"エンターテインメントには常に新しい刺激が必要なものよ。","ENG":"The entertainment industry is always in need of new stimulus.","TWN":"要有新的刺激才會有娛樂效果嘛。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그건 경기를 관람하는 대중들이나, 경기를 치르는 선수들이나 마찬가지야.","JPN":"それは試合を見る大衆も、試合に参加する選手も同じ。","ENG":"That goes for both the audience and players.","TWN":"不管對觀賞比賽的觀眾，或是對參加比賽的選手而言，都是一樣的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"매번 수작 부려서 이길 생각 말고, 가끔은 정정당당한 판을 깔아보는 건 어때?","JPN":"毎回姑息な手を使って勝とうとするんじゃなくて、たまには正々堂々と試合をしてみたらどう？","ENG":"Instead of scheming this time, why don't you create a level playing field, hmm?","TWN":"不要每次都靠耍手段贏，偶爾也試試光明正大地比賽吧，怎麼樣？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"간만에 겨뤄보고 싶은 상대가 생긴 참이거든.","JPN":"久しぶりにやりあってみたい相手もできたことだし。","ENG":"It's been a while since I felt this itch to fight someone.","TWN":"難得我久違地遇到想較量的對手呢。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"하! 말은 번지르르하군.","JPN":"ハッ！　口だけは一丁前だな。","ENG":"Hah! Again with your sly tongue.","TWN":"哈！你話說得還真好聽。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"스미스를 죽인 것도 새로운 자극인가 뭔가 때문이었나?","JPN":"スミスを殺したのも新しい刺激か何かのためだったのか？","ENG":"Was killing Smith also because of this new stimulus you keep talking about?","TWN":"你殺史密斯也是因為新的刺激嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"어머? 스미스 아저씨가 죽었어?","JPN":"あら？　スミスおじさん亡くなったの？","ENG":"Oh? Mr. Smith's dead?","TWN":"什麼？史密斯大叔死啦？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그거 안 됐네~ 그러게, 평소에 행실을 바르게 하고 다녔어야지.","JPN":"かわいそうに～だから日頃の行動には気をつけなくちゃね。","ENG":"That's a shame. But you know, he should've behaved a little better when he was alive.","TWN":"怎麼會這樣～不過也是啦，夜路走多總會遇到鬼的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"너 이 자식……!!","JPN":"貴様……！！","ENG":"Why you little...!!","TWN":"你這女人……！！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL"},{"id":"L35_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그만.","JPN":"そこまで。","ENG":"Enough.","TWN":"好了。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"무언가 착각하고 있군, 오지만디아스.","JPN":"何か勘違いをしているようだな、オジマンディアス。","ENG":"It seems that you are mistaken, Ozymandias.","TWN":"你是不是哪裡誤會了，奧茲曼迪亞斯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"우리가 제공하고 있는 상품은 엔터테인먼트가 아니야. 이미지지.","JPN":"我々が提供している商品はエンターテインメントではなく、イメージだ。","ENG":"What we provide is not entertainment. It is image.","TWN":"我們提供的商品不是娛樂，而是形象。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"우월한 스폰서를 두고 있는 팀의 압도적인 승리.","JPN":"優れたスポンサーのいるチームの圧倒的な勝利。","ENG":"The victory of a team backed by superior sponsors.","TWN":"獲得優質企業贊助的隊伍可以獲得壓倒性的勝利。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그 이미지가 기업에 투자를 만들고, 안정적인 투자는 곧 믿음으로 이어지거든.","JPN":"そのイメージが投資を引き寄せ、安定的な投資はすなわち信頼に繋がる。","ENG":"That image makes the company get more investment, and the investment leads to trust.","TWN":"這樣的形象才能為企業帶來投資，穩定的投資就會帶來信任。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"샤레이드의 사회 구조는 언제나 굳건하다는 믿음 말이야.","JPN":"シャレードの社会構造は常に堅実であるという信頼だ。","ENG":"Trust that Charade's social structure will be resilient, that is.","TWN":"而這個信任就是堅固查雷德社會結構的根基。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"호오…….","JPN":"へぇ……","ENG":"Ho-oh...","TWN":"哦……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"어차피 건틀렛 리그는 이미지를 팔기 위한 쇼에 불과해.","JPN":"ガントレットリーグは所詮、イメージを売るためのショーに過ぎない。","ENG":"Gauntlet League is a show we put on to sell that image.","TWN":"總之，聖鎧聯賽不過就是個賣弄形象的表演。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"왜 플라티나가 비싼 돈을 지불해가며 너를 지원해주는지는 알고 있을 텐데?","JPN":"なぜプラチナが高額の金を支払ってまで、君をサポートしているかは知っているな？","ENG":"I thought you knew why Platina was spending all this money to support you, did you not?","TWN":"你應該知道白金為何要投資大量金錢贊助你吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아하~ 그야 잘 알고 있지.","JPN":"それは～もちろん、よく知っているわよ。","ENG":"Oh, yes. I'm aware why.","TWN":"哈～我當然知道囉。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너무 걱정하지 마. 아무리 그 애들이 날개를 달았다고 해도 마지막 상대는 나야.","JPN":"あんまり心配しないで。いくらあの子たちが飛ぶような勢いでも、最後の相手は私よ。","ENG":"But don't worry. It doesn't matter if they grow wings and soar into the sky. In the end, they'll be facing me.","TWN":"放心，就算她有三頭六臂，但最後的對手是我。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"언제나 그랬듯, 완벽하게 짓밟아줄 테니까 말이야.","JPN":"いつものように、完璧に踏みにじってあげるわ。","ENG":"And, like always, I'll stomp on them like they're nothing.","TWN":"我會一如往常，毫不留情地踐踏她。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"아니. 그것만으로는 부족해.","JPN":"いや、それだけでは足りない。","ENG":"No, that will not be enough this time.","TWN":"不，光是這樣還不夠。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"그 재판은 정치적인 이슈였어. 정치가 얽히면 모든 게 틀어지기 마련이야.","JPN":"あの裁判は政治的に話題となった。政治が絡んでくるとあらゆるものがこじれてしまう。","ENG":"The trial was a political issue. And when politics get involved, everything gets twisted.","TWN":"那場官司是帶有政治目的的，只要扯上政治，一切就會變得複雜。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"내밀한 사정이 알려져서 좋을 게 없어. 더는 그 삼등 시민들을 내버려 둬선 안 돼.","JPN":"内密の事情が知られたら何かとまずい。これ以上あの3等市民どもを放っておくわけにはいかない。","ENG":"There is nothing good about having our internal secrets leaked. That is why those third-grade citizens should not be neglected.","TWN":"事情曝光的話沒有任何好處，不能再放著三等市民不管。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래서? 설마 도심 한 가운데서 일을 저지르려는 건 아니지?","JPN":"それで？　まさか都市のど真ん中で事を起こすつもり？","ENG":"So? Wait, you're not thinking of causing a scene in the middle of the city, are you?","TWN":"你的意思是？該不會是要在眾目睽睽之下動手？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"너무 눈에 띄는 방식은 피하는 게 좋을 걸? 대중들을 너무 무시하지 말라고.","JPN":"あんまり目立つようなことは控えた方がいいんじゃない？　大衆もそこまでバカではないわよ。","ENG":"I'd suggest you avoid anything that's too flashy. You shouldn't really underestimate the public, you know?","TWN":"這樣明目張膽不好吧？你可不要小看群眾的力量。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"우리는 우리 방식대로 행동에 나서겠다.","JPN":"我々は我々のやり方で行動を起こす。","ENG":"We have our own ways of dealing with matters like this.","TWN":"我們會照我們的方式行動。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CEO_CHARADE_NPC_CAP","text":{"KOREA":"너는 와일러의 다음 경기를 준비하도록.","JPN":"君はワイラーの次の試合に向けて準備したまえ。","ENG":"All you need to do is get Wyler ready for the next match.","TWN":"你就專心預備瓦勒的下一場比賽。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CEO_CHARADE_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"쳇, 하여간 자기 할 말만 하고 끊어버리는 건 여전하네. 멍청이들.","JPN":"ちぇっ、一方的に喋って勝手に切るのは相変わらずね、バカな奴ら。","ENG":"Tch! They always hang up after a one-sided conversation. Idiots.","TWN":"嘖，一群討厭鬼，把自己想說的話都說完後，就掛人家電話。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"뭐, 됐어. 어차피 승부는 결국 경기장 위에서 가려지겠지.","JPN":"まぁいいわ。どうせ勝負は競技場で決まるもの。","ENG":"Whatever. The match will eventually be determined in the stadium, anyway.","TWN":"算了，反正最後還是要在場上分出勝負。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그 코치라는 작자가 붙어 있는 한, 어설픈 수작이 통할 리가 없으니까.","JPN":"あのコーチという男がついている以上、下手な小細工が通用するはずはないわ。","ENG":"With that coach next to her, weak tactics won't work anyway.","TWN":"但有那個教練在，普通的小手段應該不管用。"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자, 아쉽지만 오늘 파티는 이런저런 사정으로 여기까지야~","JPN":"さて、残念だけれど、今日のパーティーはそんなこんなでこれでお開きよ～","ENG":"Oh, well. It's a shame, but the party ends here for today.","TWN":"好了好了，因為一些事情，今天的派對就到這裡～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L15_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"다음엔 경기 끝나고 진탕 마셔 보자구~","JPN":"次は試合が終わってから潰れるまで飲もう～","ENG":"Let's get our drink on after the next match, okay?","TWN":"等下一場比賽結束後再喝個過癮吧～"},"stage":{"bg":"SUMMER_HOTEL_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"이런 제기랄!!","JPN":"くそが！！","ENG":"Goddammit!!","TWN":"該死！！"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"어째서 내 마음을 몰라주는 거야!! 대체 왜……!!","JPN":"なんで俺の気持ちをわかってくれないんだ！！　どうして……！！","ENG":"Why can't you see the love I have for you!! WHY...?!","TWN":"你為什麼就是不明白我的心意！！為什麼……！！"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그새 다른 남자가 생긴거냐, 스키너!?","JPN":"俺のいない隙に違う男ができたのか、スキナー！？","ENG":"Have you got yourself another man? Is that it, Skinner?!","TWN":"你有其他男人了嗎，史金納！？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 왜 그래? 뭐가 잘 안 풀리나 봐, 와일러?","JPN":"ふふ、どうしたの？　上手くいかないことでもあった、ワイラー？","ENG":"Fu fuu, what's wrong? Something not going to plan, Wyler?","TWN":"呵呵，你幹嘛？是誰惹你不開心嗎，瓦勒？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L35_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"너도 날 무시하는 거냐, 챔피언?","JPN":"お前も俺をバカにするのか、チャンピオン？","ENG":"Are you mocking me too, champion?","TWN":"你也瞧不起我嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"에이~ 그렇게 생각하고 있다니, 섭섭하네.","JPN":"何よ～そんなふうに思われていたなんて、悲しいわ。","ENG":"C'mon, how could you think that? I feel hurt.","TWN":"討厭～你怎麼會這麼想，真是傷我的心。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"잊었어? 나는 네가 그 여자와 다시 만날 수 있도록 도와주고 있잖아?","JPN":"忘れた？　私はあなたがあの女ともう一度会えるよう手伝っているのよ？","ENG":"Did you forget? I'm the one helping you so you can see her again.","TWN":"你忘了嗎？我不是說過會幫你跟她復合？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"자, 이게 다음 경기의 엔트리야.","JPN":"はい、これが次の試合のエントリー。","ENG":"Look. This is the lineup for the next match.","TWN":"拿去，這是下一場比賽的參賽名單。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"원래 4강에 진출하기로 했던 팩토리 팀 멤버들에게는 알아듣게 설명해 놨어.","JPN":"本来ベスト4に進出するはずだったファクトリーのチームメンバーたちには納得してもらったわ。","ENG":"I already settled it with the Factory team members who were supposed to be in the semi-finals.","TWN":"我已經跟原本要晉級4強的工業隊說好了。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"그렇군. 내가 참가할 팀이 결정된 건가.","JPN":"そうか。俺が入るチームが決まったのか。","ENG":"I see. So, it's been decided which team I'll be a part of.","TWN":"是嗎？已經決定好我要加入哪隊了嗎？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"WYLER_CHARADE_NPC_NULL","text":{"KOREA":"잠깐, 이 자식들은……?","JPN":"待てよ、こいつらは……？","ENG":"Wait, these guys are...?","TWN":"等等，這些傢伙是……？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"WYLER_CHARADE_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"후후, 어때? 다들 반가운 얼굴들이지?","JPN":"ふふ、どう？　みんな懐かしい顔でしょ？","ENG":"Fu fuu, what do you think? Familiar faces, aren't they?","TWN":"呵呵，怎麼樣？都是些熟面孔吧？"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이번에는 특별히 너랑 같은 감옥을 쓰던 동기들로 섭외했으니까 말이야.","JPN":"今回は特別に、刑務所の中で同じ部屋だった同期たちでチームを組んだわ。","ENG":"I've hired the guys you shared a prison cell with, especially for you.","TWN":"這次我特別請到和你一起坐牢的牢友欸。"},"stage":{"bg":"ROOM_04","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};